const r = $input.first().json.report || {};
const c = r.current || {};
const hist = r.history_30d || [];
const color = c.color || 'gray';
const bg = color === 'green' ? '#10b981' : (color === 'yellow' ? '#f59e0b' : (color === 'red' ? '#dc2626' : '#6b7280'));
const chartHeight = 200;
const chartWidth = 1000;
const maxScore = 100;
let barsHtml = '';
if (hist.length > 0) {
  const barWidth = Math.max(8, Math.floor(chartWidth / hist.length) - 2);
  hist.forEach((h, i) => {
    const h_pct = (h.score / maxScore) * chartHeight;
    const x = i * (barWidth + 2);
    const y = chartHeight - h_pct;
    const bcolor = h.color === 'green' ? '#10b981' : (h.color === 'yellow' ? '#f59e0b' : '#dc2626');
    const dt = new Date(h.snapshot_at).toISOString().slice(5,10);
    barsHtml += '<g><rect x="'+x+'" y="'+y+'" width="'+barWidth+'" height="'+h_pct+'" fill="'+bcolor+'"><title>'+dt+': '+h.score+' ('+h.color+')</title></rect><text x="'+(x+barWidth/2)+'" y="'+(chartHeight-2)+'" text-anchor="middle" font-size="9" fill="white">'+h.score+'</text></g>';
  });
}
const card = (label, value) => '<td style="padding:14px;background:#f9fafb;border-radius:6px;width:25%;vertical-align:top"><div style="font-size:11px;color:#6b7280;text-transform:uppercase">'+label+'</div><div style="font-size:22px;font-weight:bold;color:#1f2937;margin-top:4px">'+(value!=null?value:'-')+'</div></td>';
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Health History</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 4px}h2{color:#374151;font-size:15px;margin:24px 0 8px}.meta{color:#64748b;font-size:13px}</style>' +
'</head><body>' +
'<a href="/webhook/admin-index" style="color:#2563eb;font-size:13px;text-decoration:none">← Admin index</a>' +
'<h1>Health Score History</h1>' +
'<div class="meta">Snapshot diario via cron_health_score_snapshot 06:30</div>' +
'<div style="background:'+bg+';color:white;padding:14px 20px;border-radius:8px;margin:16px 0;display:flex;align-items:center;gap:14px"><div style="font-size:36px;font-weight:bold">'+(c.score!=null?c.score:'?')+'</div><div><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;opacity:.85">Score actual</div><div style="font-size:14px;font-weight:600">'+color.toUpperCase()+'</div></div></div>' +
'<table style="width:100%;border-spacing:8px;border-collapse:separate">' +
  '<tr>' + card('Avg 30d', r.avg_30d||'-') + card('Min 30d', r.min_30d||'-') + card('Max 30d', r.max_30d||'-') + card('Dias yellow/red', (r.days_yellow_30d||0)+' / '+(r.days_red_30d||0)) + '</tr>' +
'</table>' +
'<h2>Tendencia 30 dias</h2>' +
(hist.length > 0 ?
  '<div style="background:#1f2937;padding:16px;border-radius:8px;overflow-x:auto"><svg width="'+chartWidth+'" height="'+(chartHeight+20)+'" style="display:block"><line x1="0" y1="'+(chartHeight - 0.85*chartHeight)+'" x2="'+chartWidth+'" y2="'+(chartHeight - 0.85*chartHeight)+'" stroke="#10b981" stroke-dasharray="2,2" opacity="0.5"/><line x1="0" y1="'+(chartHeight - 0.6*chartHeight)+'" x2="'+chartWidth+'" y2="'+(chartHeight - 0.6*chartHeight)+'" stroke="#f59e0b" stroke-dasharray="2,2" opacity="0.5"/>'+barsHtml+'</svg><div style="color:#9ca3af;font-size:11px;margin-top:6px">Linea verde = 85 (green threshold). Linea naranja = 60 (yellow threshold). Hover para ver fecha.</div></div>'
 : '<div style="background:white;padding:14px;border-radius:6px;color:#6b7280"><i>Aun no hay datos. El primer snapshot se grabara manana a las 06:30 (cron_health_score_snapshot).</i></div>') +
'</body></html>';
return [{ json: { html } }];
